def p_sha256(secret, seed, n):
    out = b''; a = seed
    while len(out) < n:
        a = hmac.new(secret, a, hashlib.sha256).digest()
        out += hmac.new(secret, a + seed, hashlib.sha256).digest()
    return out[:n]
def prf(secret, label, seed, n):
    return p_sha256(secret, label.encode('ascii') + seed, n)
